/**
 * Gallery Admin JavaScript
 *
 * Handles the WordPress admin functionality for gallery post type:
 * - Media library integration for adding images
 * - Image removal
 * - Drag & drop reordering with Sortable
 *
 * @package Videohub360_Theme
 * @since 1.2.0
 */

(function($) {
    'use strict';

    var VH360GalleryAdmin = {
        /**
         * Media frame instance.
         */
        frame: null,

        /**
         * Sortable instance.
         */
        sortable: null,

        /**
         * Initialize gallery admin.
         */
        init: function() {
            this.bindEvents();
            this.initSortable();
        },

        /**
         * Bind event handlers.
         */
        bindEvents: function() {
            var self = this;

            // Add images button click.
            $(document).on('click', '#vh360-gallery-add-images', function(e) {
                e.preventDefault();
                self.openMediaFrame();
            });

            // Remove image button click.
            $(document).on('click', '.vh360-gallery-image-remove', function(e) {
                e.preventDefault();
                $(this).closest('.vh360-gallery-image-item').remove();
            });
        },

        /**
         * Initialize sortable for image reordering.
         */
        initSortable: function() {
            var container = document.getElementById('vh360-gallery-images-container');
            if (!container) {
                return;
            }

            // Check if Sortable is available (it may be loaded from admin or CDN).
            if (typeof Sortable !== 'undefined') {
                this.sortable = Sortable.create(container, {
                    animation: 150,
                    ghostClass: 'sortable-ghost',
                    handle: '.vh360-gallery-image-item'
                });
            } else {
                // Fallback to jQuery UI sortable if available.
                if ($.fn.sortable) {
                    $(container).sortable({
                        placeholder: 'sortable-ghost',
                        cursor: 'move'
                    });
                }
            }
        },

        /**
         * Open WordPress media frame.
         */
        openMediaFrame: function() {
            var self = this;

            // If frame already exists, reopen it.
            if (this.frame) {
                this.frame.open();
                return;
            }

            // Create the media frame.
            this.frame = wp.media({
                title: vh360GalleryAdmin.i18n.selectImages,
                button: {
                    text: vh360GalleryAdmin.i18n.addToGallery
                },
                library: {
                    type: 'image'
                },
                multiple: true
            });

            // When images are selected.
            this.frame.on('select', function() {
                var selection = self.frame.state().get('selection');
                selection.each(function(attachment) {
                    self.addImage(attachment.toJSON());
                });
            });

            // Open the frame.
            this.frame.open();
        },

        /**
         * Add an image to the gallery container.
         *
         * @param {Object} attachment Attachment data.
         */
        addImage: function(attachment) {
            var container = $('#vh360-gallery-images-container');

            // Check if image already exists.
            if (container.find('[data-id="' + attachment.id + '"]').length > 0) {
                return;
            }

            // Get thumbnail URL (fallback to full size if no thumbnail).
            var thumbUrl = attachment.sizes && attachment.sizes.thumbnail
                ? attachment.sizes.thumbnail.url
                : attachment.url;

            // Create the image item HTML.
            var itemHtml = '<div class="vh360-gallery-image-item" data-id="' + attachment.id + '">' +
                '<img src="' + thumbUrl + '" alt="">' +
                '<button type="button" class="vh360-gallery-image-remove" aria-label="' + vh360GalleryAdmin.i18n.removeImage + '">&times;</button>' +
                '<input type="hidden" name="vh360_gallery_images[]" value="' + attachment.id + '">' +
                '</div>';

            container.append(itemHtml);
        }
    };

    // Initialize on document ready.
    $(document).ready(function() {
        VH360GalleryAdmin.init();
    });

})(jQuery);
